{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 3);
var flow = GetFloat(parameters, "flow", 0.5f);
var glowIntensity = GetFloat(parameters, "glowIntensity", 0.7f);
var magmaColor = GetColor(parameters, "magmaColor", System.Windows.Media.Color.FromRgb(255, 150, 30));
var crustColor = GetColor(parameters, "crustColor", System.Windows.Media.Color.FromRgb(40, 30, 25));
var veinDensity = GetFloat(parameters, "veinDensity", 0.5f);
var octaves = GetInt(parameters, "octaves", 3);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var mR = magmaColor.R / 255f; var mG = magmaColor.G / 255f; var mB = magmaColor.B / 255f;
var cR = crustColor.R / 255f; var cG = crustColor.G / 255f; var cB = crustColor.B / 255f;

// Generate Voronoi points for vein structure
var cellCount = (int)(scale * scale * 0.8f);
var points = new (float X, float Y, float H)[cellCount];
for (var i = 0; i < cellCount; i++)
{
    points[i] = (
        HashToUnit(i * 7, seed, 111),
        HashToUnit(i * 13, seed * 3, 222),
        HashToUnit(i * 23, seed * 7, 333)
    );
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Flow distortion
    var flowU = u + flow * TileableFractalNoise(u * 2f, v * 2f, 2, 2, 0.5f, 2f, seed) * 0.15f;
    var flowV = v + flow * TileableFractalNoise(u * 2f + 50f, v * 2f + 50f, 2, 2, 0.5f, 2f, seed + 50) * 0.15f;

    // Voronoi distance to nearest point
    var minDist = float.MaxValue;
    var nearH = 0f;
    foreach (var (px, py, h) in points)
    {
        var dx = MathF.Abs(flowU - px);
        var dy = MathF.Abs(flowV - py);
        if (dx > 0.5f) dx = 1f - dx;
        if (dy > 0.5f) dy = 1f - dy;
        var dist = dx * dx + dy * dy;
        if (dist < minDist)
        {
            minDist = dist;
            nearH = h;
        }
    }
    var voronoiDist = MathF.Sqrt(minDist);

    // Noise for crust texture
    var crustNoise = TileableFractalNoise(u * scale * 1.5f, v * scale * 1.5f, Math.Max(1, (int)MathF.Round(scale * 1.5f)), octaves, 0.5f, 2f, seed + 100);

    // Vein detection: edges of Voronoi cells
    var vein = 1f - voronoiDist * scale * 3f;
    vein = MathF.Max(0f, vein);
    vein = vein * vein * (3f - 2f * vein); // smoothstep

    // Apply vein density
    vein = MathF.Pow(vein, 1f - veinDensity * 0.5f);

    // Heat glow: bright near veins, fading with distance
    var heat = vein * glowIntensity;

    // Crust thickness variation
    var crustThickness = crustNoise * 0.4f + 0.3f;
    var crustBreak = vein > crustThickness;

    float r, g, b;
    if (crustBreak)
    {
        // Magma glow visible through crust
        var glow = MathF.Min(1f, (vein - crustThickness) * 3f);
        r = Lerp(cR, mR, glow);
        g = Lerp(cG, mG * 0.8f, glow);
        b = Lerp(cB, mB * 0.3f, glow);

        // Add pulsing heat
        var heatPulse = MathF.Sin(vein * 20f + nearH * 10f) * 0.1f + 0.9f;
        r = Math.Clamp(r * heatPulse, 0f, 1f);
        g = Math.Clamp(g * heatPulse * 0.9f, 0f, 1f);
    }
    else
    {
        // Dark crust with subtle glow above veins
        r = cR + crustNoise * 0.1f + heat * 0.2f;
        g = cG + crustNoise * 0.08f + heat * 0.1f;
        b = cB + crustNoise * 0.05f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
